#include <stdio.h>

// Basic logic functions
int NOT(int a) { return !a; }
int AND(int a, int b) { return a & b; }
int OR(int a, int b) { return a | b; }
int XOR(int a, int b) { return a ^ b; }
int NAND(int a, int b) { return !(a & b); }
int NOR(int a, int b) { return !(a | b); }
int XNOR(int a, int b) { return !(a ^ b); }

// Evaluate F = A + B.C using gates
int evaluate_F(int A, int B, int C) {
    // F = A OR (B AND C)
    int bc = AND(B, C);
    int F = OR(A, bc);
    return F;
}

int main() {
    printf("Truth Table for F = A + B.C\\n");
    printf("A B C | F\\n");
    printf("-------\\n");

    for (int A = 0; A <= 1; A++)
        for (int B = 0; B <= 1; B++)
            for (int C = 0; C <= 1; C++)
                printf("%d %d %d | %d\\n", A, B, C, evaluate_F(A, B, C));

    return 0;
}

// 2-to-1 Multiplexer using basic gates
// Inputs: A, B (data inputs), S (select line)
// Output: Y (selected output)

ALGORITHM Mux_2to1
BEGIN
  INPUT A, B, S
  OUTPUT Y

  // Method 1: Using AND-OR gates
  // Y = S'.A + S.B

  // Step 1: Invert select line
  S_not = NOT(S)

  // Step 2: AND operations
  term1 = AND(S_not, A)  // Select A when S=0
  term2 = AND(S, B)      // Select B when S=1

  // Step 3: OR operation
  Y = OR(term1, term2)

  OUTPUT Y
END

// Truth Table:
// S=0, A=X, B=anything → Y=A
// S=1, A=anything, B=X → Y=B
